import { ExamItemsMetaData } from '../../../core/metadata';
import { isSupportDataPost } from '../../../core/postDecorator';
import { FormControlEvent } from '../../../core/ControlEvent';
import { map } from '../../../decorator/controlmap';
const mainDom = require("../templates/ExamRadioBox.ejs");


@map('单选题', 'dsf.exam.radio', 'ExamRadioBox')
@isSupportDataPost(true)
export class ExamRadioBox extends dsf.Controls.ExamSubject {
    constructor(id, isPart) {
        super(id, isPart);
        this.$label = "";
        this.$metadata = ExamItemsMetaData.call(this);
        this.$value = { "text": "", "value": "" };
        this.$useVdom = true;
        this._viewRender = null;
        this.colNum = 0;
        this._items = [];
        this._realItems = [];
    }

    set value(value) {
        this.setValue(value);
        this.domUpdate();
    }
    get value() {
        return this.$value;
    }

    get items() {
        return this._items;
    }
    set items(value) {
        this._items = value;
        this.domUpdate();
    }

    initTemplate() {
        return mainDom(this)
    }

    inserted() {
        dsf.UI.render("radio", true);
    }
    updated() {
        dsf.UI.render("radio", true);
    }

    selected(item) {
        if(!this.readOnly){
            let isChange = item.value != this.value;
            this.setValue(item.value);
            this.domUpdate();
            if (isChange) {
                this.event.trigger(FormControlEvent.VALUECHANGE, { ui: this });
            }
        }
        
    }

    initEvent() {
        layui.form.on('radio(' + this.id + ')', (data) => {
            $(data.elem).val(data.value);
            let isChange = data.value != this.value;
            this.setValue(data.value);
            if (isChange) {
                this.event.trigger(FormControlEvent.VALUECHANGE, { ui: this });
            }
        });
    }

    getColumnWidth() {
        let colNum = parseInt(this.colNum) || 0;
        let width = !colNum ? "100%" : (100 / colNum) + "%";
        return width;
    }

    getItemsByMetaData() {
        if (this.metadata.dataSource && this.metadata.dataSource.type == "static") {
            this.items = this.metadata.dataSource.code;
        }
    }

    getAnswer() {
        let arr = [];
        this.items.forEach((item, i) => {
            var c = _.find(this.$answer, (v) => { return v == item.value });
            c && arr.push(dsf.Math.numToEnglishLetter(i + 1));
        });
        return arr;
    }

    setValue(value) {
        let type = $.type(value);
        let _this = this;
        var l = this.items;
        this.items.forEach((item) => {
            if (type == "string") {
                item.value == value && (_this.$value = item);
            } else {
                item.value == value.value && (_this.$value = item);
            }
        });
        this._answered = this.isAnswered();
        this.commit();
    }

    isChecked(cur) {
        if (dsf.isDef(this.$value)) {
            let type = $.type(this.$value);
            if (type == "string") {
                return cur == this.$value;
            } else {
                return cur == this.$value.value;
            }
        }
        return false;
    }

    resultHigh(cur) {
        if (this.$answer && this.$answer.length > 0) {
            let result = _.find(this.$answer, (v) => v == cur);
            let isChecked = this.$value.value == cur;
            if (result) {
                return 'right'
            } else {
                return isChecked ? 'error' : '';
            }
        }
        return '';
    }

    isRight() {
        if (this.$answer && this.$answer.length > 0) {
            return this.$answer[0] == this.$value.value ? 1 : 0;
        }
        return null;
    }

    isAnswered() {
        return this.value && this.value.value;
    }
}