import { SubjectiveMetaData } from "../../../core/metadata";
import { isSupportDataPost } from "../../../core/postDecorator";
import { FormControlEvent } from "../../../core/ControlEvent";
import { map } from "../../../decorator/controlmap";
import mainDom from "../templates/ExamSubjective.ejs";

@map("主观题", "dsf.exam.subjective", "ExamSubjective")
@isSupportDataPost(true)
export class ExamSubjective extends dsf.Controls.ExamSubject {
  constructor(id, isPart) {
    super(id, isPart);
    this.$label = "";
    this.$metadata = SubjectiveMetaData.call(this);
    // 值
    this.$value = "";
    this.$placeholder = "请输入";
    this.$isTextArea = false;
    this.$maxLength = 200;
  }

  set value(value) {
    this.setValue(value);
    this.domUpdate();
  }
  get value() {
    return this.$value;
  }

  get items() {
    return this._items;
  }
  set items(value) {
    this._items = value;
    this.domUpdate();
  }

  initTemplate() {
    return mainDom(this);
  }

  render() {
    super.render();
  }
  resize() {
    super.resize();
  }

  initEvent() {
    let _this = this;
    super.initEvent();
    this.element.on("input propertychange", "textarea.filltext", function(evt) {
      let currentInput = $(evt.target);
      _this.setValue(currentInput.val());
    });
  }

  getAnswer() {
    let arr = [];
    this.items.forEach((item, i) => {
      var c = _.find(this.$answer, (v) => {
        return v == item.value;
      });
      c && arr.push(dsf.Math.numToEnglishLetter(i + 1));
    });
    return arr;
  }

  setValue(value) {
    this.$value = value;
    this.items = value;
    this._answered = this.isAnswered();
    this.commit();
  }

  resultHigh(cur, index) {
    if (this.$answer && this.$answer.length) {
      return this.$answer[index - 1] === cur[index - 1] ? "right" : "error";
    }
    return "";
  }

  isRight() {
    // 没有做数据提交判断是否正确。 直接返回一个3
    // if (this.$answer && this.$answer.length > 0) {
    //   return this.$answer[0] == this.$value ? 1 : 0;
    // }
    return 3;
  }

  isAnswered() {
    return this.value ? true : false;
  }
}
