import { ExamItemsMetaData } from '../../../core/metadata';
import { isSupportDataPost } from '../../../core/postDecorator';
import { FormControlEvent } from '../../../core/ControlEvent';
import { map } from '../../../decorator/controlmap';
const mainDom = require("../templates/ExamTrueOrFlase.ejs");


@map('是非题', 'dsf.exam.trueorfalse', 'ExamTrueOrFlase')
@isSupportDataPost(true)
export class ExamTrueOrFlase extends dsf.Controls.ExamSubject {
    constructor(id, isPart) {
        super(id, isPart);
        this.$label = "";
        this.$metadata = ExamItemsMetaData.call(this);
        this.$value = { "text": "", "value": "" };
        this._items = [{ "text": "正确", "value": "正确" }, { "text": "错误", "value": "错误" }];
    }

    set value(value) {
        this.setValue(value);
        this.domUpdate();
    }
    get value() {
        return this.$value;
    }

    get items() {
        return this._items;
    }
    set items(value) {
        if (value) {
            this._items = value;
            this.domUpdate();
        }
    }

    initTemplate() {
        return mainDom(this)
    }

    inserted() {
        dsf.UI.render("radio", true);
    }
    updated() {
        dsf.UI.render("radio", true);
    }


    getAnswer() {
        let arr = [];
        this.items.forEach((item, i) => {
            var c = _.find(this.$answer, (v) => { return v == item.value });
            c && arr.push(dsf.Math.numToEnglishLetter(i + 1));
        });
        return arr;
    }


    selected(item) {
        if (!this.readOnly) {
            let isChange = item.value != this.value;
            this.setValue(item.value);
            this.domUpdate();
            if (isChange) {
                this.event.trigger(FormControlEvent.VALUECHANGE, { ui: this });
            }
        }

    }

    initEvent() {
        let _this = this;
        layui.form.on('radio(' + this.id + ')', function(data) {
            $(data.elem).val(data.value);
            let isChange = data.value != _this.value;
            _this.setValue(data.value);
            if (isChange) {
                _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
            }
        });
    }

    setValue(value) {
        let type = $.type(value);
        this.items.forEach((item) => {
            if (type == "string") {
                if (item.value == value) {
                    this.$value = item;
                }
            } else {
                if (item.value == value.value) {
                    this.$value = item;
                }
            }
        });
        this._answered = this.isAnswered();
        this.commit();
    }

    isChecked(cur) {
        let type = $.type(this.$value);
        if (type == "string") {
            return cur == this.$value;
        } else {
            return cur == this.$value.value;
        }
    }

    resultHigh(cur) {
        if (this.$answer.length > 0) {
            let result = _.find(this.$answer, (v) => v == cur);
            let isChecked = this.$value.value == cur;
            if (result) {
                return 'right';
            } else {
                return isChecked ? 'error' : '';
            }
        }
        return '';
    }
    isRight() {
        if (this.$answer && this.$answer.length > 0) {
            if (this.$answer[0] == this.$value.value) {
                return 1;
            } else {
                return 0;
            }
        }
        return null;
    }

    isAnswered() {
        if (this.value && this.value.value) {
            return true;
        }
        return false;
    }
}