import { ExamFillMetaData } from '../../../core/metadata';
import { isSupportDataPost } from '../../../core/postDecorator';
import { FormControlEvent } from '../../../core/ControlEvent';
import { map } from '../../../decorator/controlmap';
const mainDom = require("../templates/ExamFill.ejs");

const inputMinWidth = 60; //对应html中也要修改
const inputMaxWidth = 300; //对应html中也要修改

@map('填空题', 'dsf.exam.fill', 'ExamFill')
@isSupportDataPost(true)
export class ExamFill extends dsf.Controls.ExamSubject {
    constructor(id, isPart) {
        super(id, isPart);
        this.$label = "";
        this.$metadata = ExamFillMetaData.call(this);
        this.$value = {};
        // this._inputWidths = {}
        this._inputCount = 0;
        this.$chatLength = [1];
        // this._isTrim=true;
    }

    set value(value) {
        this.setValue(value);
        this.domUpdate();
    }
    get value() {
        return this.$value;
    }

    initTemplate() {
        return mainDom(this);
    }

    //将题干中的（）转换为文本框
    parseContent() {
        this._inputCount = 0;
        let reg = /(\(\s*\)|（\s*）)/gim;
        let _this = this,
            count = 1,
            tokens = [],
            idx = 0,
            sindex, result;
        let str = this.$questionBody;
        while (result = reg.exec(str)) {
            sindex = result.index;
            let s = str.slice(idx, sindex);
            idx = result.index + result[0].length;
            s && tokens.push(s);
            let inputs = _this.createInput(count);
            _.each(inputs, (input) => {
                tokens.push(input);
            });
            count++;
            this._inputCount++;
        }
        if (idx <= str.length) {
            let s = str.slice(idx, str.length);
            if (s) {
                tokens.push(s);
            }
        }
        if (!tokens.length) {
            if (!str) {
                tokens = null;
            } else {
                tokens = [str];
            }
        }
        let value = [];
        let currValue = valueToArray(this.$value);
        if (this._inputCount > 1) {
            for (let i = 0; i < this._inputCount; i++) {
                value.push("");
            }

        } else {
            value.push("");
        }
        for (let i = 0; i < currValue.length; i++) {
            if (dsf.isDef(value[i])) {
                value[i] = currValue[i];
            }
        }
        this.$value = arrayToValue(value);
        if (tokens) {
            return tokens.join("");
        }
        return ""
    }

    //创建文本框虚拟dom
    createInput(index) {
        let _this = this;
        let value = valueToArray(this.$value);
        let key = "text_" + index;
        let chatLength = _this.$chatLength[index - 1] || 1;
        let content = value[index - 1] || "";
        let inputs = [];
        let r = this.resultHigh(value, index);
        for (let i = 0; i < chatLength; i++) {
            let v = content[i] || ""
            let str = '<input class="filltext ' + (r) + '" ' + (this.readOnly ? 'readonly' : '') + ' chat-index="' + i + '" type="text" placeholder="" index="' + index + '" autocomplete="off" name="' + key + '" value="' + v + '">';
            inputs.push(str)
        }
        return inputs;
    }

    resize() {
        super.resize();
    }

    initEvent() {
        let _this = this;
        super.initEvent();
        let mark = false;
        let isComposition = false;
        //文本框定位，聚焦的时候找到第一个为空的作为定位，如果没找到，定位到最后一个文本框
        this.element.on("click focus", "input.filltext", function(evt) {
            let currentInput = $(evt.target);
            if (!mark) {
                mark = true;
                let currentInput = $(evt.target);
                let name = currentInput.attr("name");
                let inputs = _this.element.find('input[name=' + name + ']');
                let focusInput = null;
                for (let i = 0; i < inputs.length; i++) {
                    if (!inputs[i].value) {
                        focusInput = inputs[i];
                        break;
                    }
                }
                if (!focusInput) {
                    focusInput = inputs.get(inputs.length - 1);
                }
                if (evt.type == "click") {
                    focusInput.blur();
                }
                focusInput.focus();
            } else {
                mark = false;
                //将光标移动的到当前文本框内容最后
                moveToEnd(currentInput.get(0))
            }
            evt.preventDefault();
        });
        //监听输入法输入完成,输入完成切分字符
        this.element.on("compositionstart", "input.filltext", function(evt) {
            isComposition = true;
        });
        this.element.on("compositionend", "input.filltext", function(evt) {
            let input = $(evt.target);
            let content = $.trim(input.val());
            let groupIndex = input.attr('index');
            let chatIndex = input.attr('chat-index');
            splitValue(content, chatIndex, input.attr('index'));
            _this.setGroupInputValue(groupIndex);
            isComposition = false;
        });
        //切分字符
        this.element.on("input", "input.filltext", function(evt) {
            if (!isComposition) {
                let input = $(evt.target);
                let content = $.trim(input.val());
                let groupIndex = input.attr('index');
                let chatIndex = input.attr('chat-index');
                splitValue(content, chatIndex, input.attr('index'));
                _this.setGroupInputValue(groupIndex);
            }
        });
        //监听删除键
        this.element.on("keydown", "input.filltext", function(evt) {
            if (evt.keyCode == 8) {
                let input = $(evt.target);
                let inputsGroupIndex = input.attr("index");
                let charIndex = input.attr("chat-index");
                let v = input.val();
                if (!v) {
                    charIndex--;
                    if (charIndex < 0) {
                        charIndex = 0;
                    }
                    let preInput = _this.element.find("input[index=" + inputsGroupIndex + "][chat-index=" + charIndex + "]");
                    preInput.val("");
                }
                let content = _this.getGroupInputValue(inputsGroupIndex);
                splitValue(content, 0, inputsGroupIndex);
                input.focus();
                _this.setGroupInputValue(inputsGroupIndex);
            }
        });


        function splitValue(content, pos, inputsGroupIndex) {
            content = $.trim(content);
            console.log(content.length);
            let arr = content.split('');
            let lastInput = null;
            while (arr.length > 0) {
                let chat = arr.shift();
                let ipt = _this.element.find("input[index=" + inputsGroupIndex + "][chat-index=" + pos + "]");
                if (ipt.length) {
                    ipt.val(chat);
                    lastInput = ipt;
                    pos++;
                }
                if (arr.length == 0) {
                    lastInput.focus();
                }
            }
        }
    }

    setValue(value) {
        let v = valueToArray(value);
        for (let i = 0; i < v.length; i++) {
            let str = v[i];
            let chatLength = this.$chatLength[i] || 1;
            v[i] = str.substr(0, chatLength)
        }
        v = arrayToValue(v);
        this.$value = v;
        this._answered = this.isAnswered();
        this.commit();
    }

    setGroupInputValue(inputsGroupIndex) {
        let content = this.getGroupInputValue(inputsGroupIndex);
        let key = "text_" + inputsGroupIndex;
        if (this._inputCount > 1) {
            this.$value[key] = content;
        } else {
            this.$value = content;
        }
        this._answered = this.isAnswered();
        this.commit();
    }

    getGroupInputValue(inputsGroupIndex) {
        let inputs = this.element.find("input[index=" + inputsGroupIndex + "]");
        let content = "";
        inputs.each((i, el) => {
            content += el.value;
        });
        return content;
    }

    createMetaData() {
        let m = super.createMetaData();
        if (m) {
            let meta = m.md;
            meta.valueAttributes = [];
            for (let i = 0; i < this._inputCount; i++) {
                meta.valueAttributes.push({
                    "name": "文本" + (i + 1),
                    "code": "text_" + (i + 1),
                    "type": { text: "文本", value: "string" },
                    "length": "100",
                    "defaultValue": null,
                    "unit": null
                });
            }
            return m;
        }
        return null;
    }

    resultHigh(cur, index) {
        if (this.$answer && this.$answer.length) {
            return this.$answer[index - 1] === cur[index - 1] ? 'right' : 'error';
        }
        return '';
    }

    isRight() {
        if (this.$answer && this.$answer.length) {
            let valueArr = valueToArray(this.$value);
            let temp = [];
            for (let i = 0; i < this.$answer.length; i++) {
                this.$answer[i] == valueArr[i] && temp.push(true);
            }
            if (temp.length == this.$answer.length) {
                return 1;
            } else {
                return 0;
            }
        }
        return null;
    }

    isAnswered() {
        let v = valueToArray(this.$value);
        let temp = 0;
        for (var i = 0; i < v.length; i++) {
            v[i] && temp++;
        }
        if (temp == this._inputCount) {
            return true;
        }
        return false;
    }
}


function moveToEnd(el) {
    if (typeof el.selectionStart == "number") {
        el.selectionStart = el.selectionEnd = el.value.length;
    } else if (typeof el.createTextRange != "undefined") {
        el.focus();
        var range = el.createTextRange();
        range.collapse(false);
        range.select();
    }
}

function valueToArray(value) {
    let v = [];
    let type = $.type(value);
    if (type == "object") {
      for (let k in value) {
        v.push(value[k]);
      }
    } else if (type == "string") {
      v.push(value);
    } else if (type == "array") {
      v = value;
    }
    return v;
  }

function arrayToValue(arr) {
    let v;
    if (arr.length <= 1) {
        v = arr[0] || "";
    } else {
        v = {};
        for (let i = 0; i < arr.length; i++) {
            v["text_" + (i + 1)] = $.trim(arr[i]);
        }
    }
    return v;
}