import { ExamItemsMetaData } from '../../../core/metadata';
import { isSupportDataPost } from '../../../core/postDecorator';
import { FormControlEvent } from '../../../core/ControlEvent';
import { map } from '../../../decorator/controlmap';
const mainDom = require("../templates/ExamCheckBox.ejs");

@map('多选题', 'dsf.exam.checkbox', 'ExamCheckBox')
@isSupportDataPost(true)
export class ExamCheckBox extends dsf.Controls.ExamSubject {
    constructor(id, isPart) {
        super(id, isPart);
        this.$label = "";
        this.$metadata = ExamItemsMetaData.call(this);
        this.$value = [];
        this._vdom = null;
        this.colNum = 0;
        this._items = [];
        this._realItems = [];
    }

    set value(value) {
        this.setValue(value);
        this.domUpdate();
    }
    get value() {
        return this.$value;
    }

    get items() {
        return this._items;
    }
    set items(value) {
        this._items = value;
        this.domUpdate();
    }

    initTemplate() {
        return mainDom(this);
    }

    inserted() {
        dsf.UI.render("checkbox", true);
    }

    updated() {
        dsf.UI.render("checkbox", true);
    }

    selected(item) {
        if(!this.readOnly){
            let result = _.find(this.$value, (v) => v.value == item.value);
            result ? this.removeValue(item.value) : this.addValue(item.value)
            this.domUpdate();
            this.event.trigger(FormControlEvent.VALUECHANGE, { ui: this });
        }
       
    }


    initEvent() {
        let _this = this;
        layui.form.on('checkbox(' + this.id + ')', function(data) {
            $(data.elem).val(data.value);
            data.elem.checked ? _this.addValue(data.value) : _this.removeValue(data.value);
            _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
        });
    }

    getAnswer() {
        let arr = [];
        this.items.forEach((item, i) => {
            var c = _.find(this.$answer, (v) => v == item.value);
            c && arr.push(dsf.Math.numToEnglishLetter(i + 1));
        });
        return arr;
    }

    setValue(value) {
        let _this = this;
        let val = $.isArray(value) ? value : [value];
        let result = [];
        val.forEach(v => {
            let type = $.type(v);
            let itemValue = type == "object" ? v.value : v;
            let item = _.find(_this.items, (item) => item.value == itemValue);
            item && result.push(item);
        });
        result = _.uniqWith(result, (v1, v2) => v1.value == v2.value);
        result = itemsSort(this, result);
        this.$value = result;
        this._answered = this.isAnswered();
        this.commit();
    }

    addValue(value) {
        let type = $.type(value);
        let val = type == "string" ? value : value.value;
        let item = _.find(this.items, v => v.value == val);
        item && this.$value.push(item);
        this.$value = _.uniqWith(this.$value, (v1, v2) => v1.value == v2.value);
        this.$value = itemsSort(this, this.$value);
        this._answered = this.isAnswered();
        this.commit();
    }

    removeValue(value) {
        let type = $.type(value);
        let val = type == "string" ? value : value.value;
        _.remove(this.$value, (v) => v.value == val);
        this.$value = _.uniqWith(this.$value, (v1, v2) => v1.value == v2.value);
        this.$value = itemsSort(this, this.$value);
        this._answered = this.isAnswered();
        this.commit();
    }

    isChecked(cur) {
        let isChecked = false;
        this.$value.forEach(o => {
            o.value == cur && (isChecked = true)
        });
        return isChecked;
    }

    resultHigh(cur) {
        if (this.$answer.length > 0) {
            let isChecked = false;
            if (this.$value) {
                isChecked = _.find(this.$value, (v) => {
                    return v.value == cur;
                });
            }
            if (isChecked) {
                let r = this.isRight();
                if (r === 1) {
                    return 'right'
                } else if (r === 0) {
                    return 'error';
                }
            }
        }
        return '';
    }

    isRight() {
        if (this.$answer && this.$answer.length) {
            //选项数量与正确答案不符合视为错误
            if (this.$answer.length != this.$value.length) {
                return 0;
            }
            //选项与正确答案比对
            let temp = [];
            let value = this.$value;
            this.$answer.forEach(a => {
                value.forEach(v => {
                    if (v.value == a) {
                        temp.push(true);
                    }
                });
            });
            if (temp.length != this.$answer.length) {
                return 0;
            }
            return 1;
        }
        return null;
    }

    isAnswered() {
        if (this.value && this.value.length) {
            return true;
        }
        return false
    }

    getColumnWidth() {
        let colNum = parseInt(this.colNum) || 0;
        let width = !colNum ? "100%" : (100 / colNum) + "%";
        return width;
    }

    getItemsByMetaData() {
        if (this.metadata.dataSource && this.metadata.dataSource.type == "static") {
            this.items = this.metadata.dataSource.code;
        }
    }


}

function itemsSort(ctrl, arr) {
    arr = arr || [];
    let newArr = arr.sort((v1, v2) => {
        let idx1 = _.findIndex(ctrl._realItems, o => o.value == v1.value);
        let idx2 = _.findIndex(ctrl._realItems, o => o.value == v2.value);
        if (idx1 < idx2) {
            return -1;
        } else if (idx1 > idx2) {
            return 1;
        }
        return 0;
    })
    return newArr;
}